// Parse Neo4j HTTP responses into usable context
const statsResponse = $('4. Get Graph Stats (HTTP)').first().json;
const companyResponse = $('5. Get Company Data Map (HTTP)').first().json;
const question = $('2. Prepare Input').first().json.question;
const sessionId = $('2. Prepare Input').first().json.sessionId;

// Extract results from Neo4j HTTP format
let graphStats = [];
let companyData = [];

try {
  if (statsResponse.results && statsResponse.results[0] && statsResponse.results[0].data) {
    graphStats = statsResponse.results[0].data.map(d => ({
      nodeType: d.row[0],
      count: d.row[1]
    }));
  }
} catch (e) {
  graphStats = [{ error: 'Could not retrieve graph stats' }];
}

try {
  if (companyResponse.results && companyResponse.results[0] && companyResponse.results[0].data) {
    companyData = companyResponse.results[0].data.map(d => ({
      company: d.row[0],
      dataTypes: d.row[1],
      dataPoints: d.row[2]
    }));
  }
} catch (e) {
  companyData = [{ error: 'Could not retrieve company data' }];
}

const hasData = graphStats.length > 0 && !graphStats[0].error;

return {
  json: {
    question,
    sessionId,
    graphStats,
    companyData,
    hasData,
    contextPrepared: true
  }
};

