// Parse AI response and format for natural language
const aiOutput = $input.first().json.output || $input.first().json.text || '';
const question = $('2. Prepare Input').first().json.question;
const sessionId = $('2. Prepare Input').first().json.sessionId;

let response;

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    response = JSON.parse(jsonMatch[0]);
  } else {
    // Use raw text as answer
    response = {
      answer: aiOutput,
      graphNodes: [],
      suggestedQueries: [
        "What companies have my email?",
        "What's my biggest privacy risk?",
        "Show me all my accounts"
      ],
      riskAlerts: [],
      actionItems: []
    };
  }
} catch (e) {
  response = {
    answer: aiOutput,
    graphNodes: [],
    suggestedQueries: [],
    riskAlerts: [],
    actionItems: [],
    parseError: e.message
  };
}

// Ensure answer is natural language (not JSON)
if (typeof response.answer === 'object') {
  response.answer = JSON.stringify(response.answer);
}

return {
  json: {
    success: true,
    sessionId: sessionId,
    question: question,
    ...response,
    respondedAt: new Date().toISOString()
  }
};
